LPCTSTR const szShortcutExtension = _T("lnk");

LPCTSTR	const szUserProgramsPathRegistryKey = _T("Software\\Microsoft\\Windows\\CurrentVersion\\Explorer\\Shell Folders");
LPCTSTR const szUserProgramsPathValueName = _T("Programs");
LPCTSTR	const szUserProgramsDefaultDirectory = _T("\\Start Menu\\Programs");

LPCTSTR const szCommonProgramsPathRegistryKey = _T("Software\\Microsoft\\Windows\\CurrentVersion\\Explorer\\Shell Folders");
LPCTSTR const szCommonProgramsPathValueName = _T("Common Programs");
LPCTSTR	const szCommonProgramsDefaultDirectory = _T("\\Start Menu\\Programs");

LPCTSTR const szCommonStartupPathValueName = _T("Common Startup");
LPCTSTR const szStartupPathValueName = _T("Startup");
LPCTSTR	const szCommonStartupDefaultDirectory = _T("\\Start Menu\\Startup");


