CShellClient::CShellClient ()
/*
	Effect		Initialize this CShellClient object and it's data members.
				Establish whether the object should communicate with the
				system via the shell interface or use the older DDE method.
*/
{
	m_pShellLink = NULL;
	m_pPersistFile = NULL;

	//////////////////////////////////////
	// Use shell interface?
	//////////////////////////////////////

#ifdef _WIN32
	//////////////////////////////////////
	// Determine Shortcut Paths
	//////////////////////////////////////

	//// Determine current user programs path 

	CString RegisteredUserShortcutPath;
	SafeGetRegistryKeyString(HKEY_CURRENT_USER, szUserProgramsPathRegistryKey, szUserProgramsPathValueName, RegisteredUserShortcutPath);
//	CRegistryString	RegisteredUserShortcutPath (HKEY_CURRENT_USER,
//												szUserProgramsPathRegistryKey,
//												szUserProgramsPathValueName);
	m_UserProgramsShortcutPath.SetDriveDirectory (RegisteredUserShortcutPath);
	if (m_UserProgramsShortcutPath.IsEmpty())
	{
		m_UserProgramsShortcutPath.WindowsDirectory();
		m_UserProgramsShortcutPath.AppendDirectory (szUserProgramsDefaultDirectory);
	}

	//// Determine common programs path

	OSVERSIONINFO ovi;
	ovi.dwOSVersionInfoSize = sizeof(OSVERSIONINFO);
	VERIFY(::GetVersionEx(&ovi));
	if (ovi.dwPlatformId == VER_PLATFORM_WIN32_NT)
	{
		CString RegisteredCommonShortcutPath;
		SafeGetRegistryKeyString(HKEY_LOCAL_MACHINE, szCommonProgramsPathRegistryKey, szCommonProgramsPathValueName, RegisteredCommonShortcutPath);
//		CRegistryString	RegisteredCommonShortcutPath (HKEY_LOCAL_MACHINE,
//													  szCommonProgramsPathRegistryKey,
//													  szCommonProgramsPathValueName);
		m_CommonProgramsShortcutPath.SetDriveDirectory (RegisteredCommonShortcutPath);
		if (m_CommonProgramsShortcutPath.IsEmpty())
		{
			m_CommonProgramsShortcutPath.WindowsDirectory();
			m_CommonProgramsShortcutPath.AppendDirectory (szCommonProgramsDefaultDirectory);
		}
	}
	else
	{
		// Windows 95 doesn't have a separate spot for common shortcuts.
		m_CommonProgramsShortcutPath = m_UserProgramsShortcutPath;
	}

	CString RegisteredCommonStartupPath;
	if (SafeGetRegistryKeyString(HKEY_LOCAL_MACHINE, szCommonProgramsPathRegistryKey, szCommonStartupPathValueName, RegisteredCommonStartupPath) != ERROR_SUCCESS)
	{
		SafeGetRegistryKeyString(HKEY_CURRENT_USER, szCommonProgramsPathRegistryKey, szStartupPathValueName, RegisteredCommonStartupPath);
	};
	m_CommonStartupShortcutPath.SetDriveDirectory (RegisteredCommonStartupPath);
	if (m_CommonStartupShortcutPath.IsEmpty())
	{
		m_CommonStartupShortcutPath.WindowsDirectory();
		m_CommonStartupShortcutPath.AppendDirectory (szCommonStartupDefaultDirectory);
	}
#endif	// _WIN32
}


CShellClient::~CShellClient()
{
	if (m_pShellLink != NULL)
		Disconnect();
}



BOOL CShellClient::Connect (BOOL bStartIfNeeded)
{
	HRESULT			hResult;

	hResult = CoInitialize (NULL);
	hResult = CoCreateInstance (CLSID_ShellLink,	// class identifier
								NULL,				// not an aggregate
								CLSCTX_INPROC_SERVER,
								IID_IShellLink,
								(void**)&m_pShellLink);
	if (SUCCEEDED (hResult))
		hResult = m_pShellLink->QueryInterface(IID_IPersistFile, 
						(void **)&m_pPersistFile);

	return (SUCCEEDED (hResult));
}

BOOL CShellClient::Disconnect ()
{
	if (m_pPersistFile != NULL)
	{
		m_pPersistFile->Release();
		m_pPersistFile = NULL;
	}
	if (m_pShellLink != NULL)
	{
		m_pShellLink->Release();
		m_pShellLink = NULL;
	}
	return TRUE;
}


BOOL CShellClient::CreateGroup (LPCTSTR lpszGroupName, 
								LPCTSTR lpszGroupFile /*= NULL*/)
{
	CPath		ShortcutPath;

	SetShortcutGroupPath (ShortcutPath, lpszGroupName, TRUE);
	return ShortcutPath.CreateDirectory();
}

BOOL CShellClient::DeleteGroup (LPCTSTR lpszGroupName, BOOL bRemoveIfNotEmpty)
{
	CPath		ShortcutPath;
	SetShortcutGroupPath (ShortcutPath, lpszGroupName, TRUE);
	if (bRemoveIfNotEmpty)
	{
		return NavoRemoveDirectoryTree(CString((LPCTSTR)ShortcutPath));
	}
	else
	{
		return ShortcutPath.RemoveDirectory();
	};
}

