BOOL CShellClient::DeleteItem (LPCTSTR lpszGroup, LPCTSTR lpszDescription)
{
	CPath	ShortcutPath;
	SetShortcutPath (ShortcutPath, lpszGroup, lpszDescription, TRUE);
	return ShortcutPath.Delete();
}


