BOOL CShellClient::CreateProgramItem (LPCTSTR lpszGroupName,
											  LPCTSTR lpszProgramPath,
										 	  LPCTSTR lpszArguments,
											  LPCTSTR lpszCaption,
											  LPCTSTR lpszIconPath /*= NULL*/,
											  UINT nIcon /*= 0*/,
											  LPCTSTR lpszWorkingDirectory /*= NULL*/,
											  int nHotKey /*= -1*/,
											  int nCmdShow /*= SW_SHOW*/)
{
	CString oGroupNameString(lpszGroupName);
	bool bSpecialGroup = false;
	if (oGroupNameString.GetLength() > 2 && oGroupNameString.GetAt(0) == '@' && oGroupNameString.GetAt(oGroupNameString.GetLength() - 1) == '@')
	{
		bSpecialGroup = true;
		oGroupNameString = CString((LPCTSTR)oGroupNameString + 1, oGroupNameString.GetLength() - 2);
		if (!oGroupNameString.CompareNoCase("startup"))
		{
			oGroupNameString = (LPCTSTR)m_CommonStartupShortcutPath;
		}
		else
		if (!oGroupNameString.CompareNoCase("desktop"))
		{
			oGroupNameString = (LPCTSTR)_get_desktop_shelllink_path();
		}
		else
		{
			ASSERT(false);
		};
	};

	Connect ();

	CPath		ShortcutGroupPath;
	CPath		ShortcutPath;
	if (bSpecialGroup)
	{
		ShortcutGroupPath = oGroupNameString;
		ShortcutPath.SetDriveDirectory(oGroupNameString);
		ShortcutPath.SetName(CString(lpszCaption) + '.' + szShortcutExtension);
	}
	else
	{
		SetShortcutGroupPath (ShortcutGroupPath, oGroupNameString, TRUE);
		SetShortcutPath (ShortcutPath,
						 oGroupNameString, 
						 lpszCaption, 
						 TRUE);
	}
	ShortcutGroupPath.CreateDirectory ();

	CString oWorkingDirectoryStr;
	if (lpszWorkingDirectory)
	{
		oWorkingDirectoryStr = lpszWorkingDirectory;
	}
	else
	{
		CString oProgramPathStr(lpszProgramPath);
		long lNameIndex = oProgramPathStr.ReverseFind('\\');
		if (lNameIndex == -1)
		{
			lNameIndex = oProgramPathStr.ReverseFind('/');
		};
		if (lNameIndex != -1)
		{
			oWorkingDirectoryStr = CString(lpszProgramPath, lNameIndex);
		};
	};

	m_pShellLink->SetPath (lpszProgramPath);
	m_pShellLink->SetArguments (lpszArguments);
	m_pShellLink->SetDescription (lpszCaption);
	m_pShellLink->SetWorkingDirectory(oWorkingDirectoryStr);

#ifndef _UNICODE
	int nLen = MultiByteToWideChar(CP_ACP,	
						0, 
						ShortcutPath, 
						strlen(ShortcutPath), 
						NULL, 
						0);
	LPWSTR wszShortcutPath = new WCHAR[nLen+1];
	
	MultiByteToWideChar(CP_ACP,	
						0, 
						ShortcutPath, 
						strlen(ShortcutPath), 
						wszShortcutPath, 
						nLen);

	wszShortcutPath[nLen] = '\0';	//assure null termination

	HRESULT hResult = m_pPersistFile->Save (wszShortcutPath, TRUE);
	delete[] wszShortcutPath;
#else
	HRESULT hResult = m_pPersistFile->Save (ShortcutPath, TRUE);
#endif
	Disconnect();
	return (SUCCEEDED (hResult));
}


// virtual 
BOOL CShellClient::RemoveProgramItem (LPCTSTR lpszGroupName,
									 LPCTSTR lpszCaption)
{
	CString oGroupNameString(lpszGroupName);
	bool bSpecialGroup = false;
	if (oGroupNameString.GetLength() > 2 && oGroupNameString.GetAt(0) == '@' && oGroupNameString.GetAt(oGroupNameString.GetLength() - 1) == '@')
	{
		bSpecialGroup = true;
		oGroupNameString = CString((LPCTSTR)oGroupNameString + 1, oGroupNameString.GetLength() - 2);
		if (!oGroupNameString.CompareNoCase("startup"))
		{
			oGroupNameString = (LPCTSTR)m_CommonStartupShortcutPath;
		}
		else
		if (!oGroupNameString.CompareNoCase("desktop"))
		{
			oGroupNameString = (LPCTSTR)_get_desktop_shelllink_path();
		}
		else
		{
			ASSERT(false);
		};
	};
	CPath		ShortcutPath;

	if (bSpecialGroup)
	{
		ShortcutPath.SetDriveDirectory(oGroupNameString);
		ShortcutPath.SetName(CString(lpszCaption) + '.' + szShortcutExtension);
	}
	else
	{
		SetShortcutPath (ShortcutPath,
						 oGroupNameString,
						 lpszCaption,
						 TRUE);
	}
	return ShortcutPath.Delete ();
}


// virtual 
BOOL CShellClient::RemoveProgramGroup (LPCTSTR lpszGroupName,
										BOOL bRemoveIfNotEmpty /*= FALSE*/)
{
	return DeleteGroup (lpszGroupName, bRemoveIfNotEmpty);
}



