// protected
void CShellClient::SetShortcutProgramsPath (CPath& rPath, 
											BOOL bCommonShortcut) const
{
	if (bCommonShortcut)
		rPath = m_CommonProgramsShortcutPath;
	else
		rPath = m_UserProgramsShortcutPath;
}


// protected
void CShellClient::SetShortcutGroupPath (CPath& rPath,
										 LPCTSTR lpszGroupName,
										 BOOL bCommonShortcut) const
{
	SetShortcutProgramsPath (rPath, bCommonShortcut);
	rPath.AppendDirectory (lpszGroupName);
}


// protected
void CShellClient::SetShortcutPath (CPath& rPath,
									LPCTSTR lpszGroupName,
									LPCTSTR lpszCaption,
								    BOOL bCommonShortcut) const
{
	SetShortcutGroupPath (rPath, lpszGroupName, bCommonShortcut);

	rPath.SetName (CString(lpszCaption) + '.' + szShortcutExtension);
//	rPath.SetExtension (szShortcutExtension);
}


CString CShellClient::_get_desktop_shelllink_path()
{
	return _get_special_folder_path(nsf_desktop);
}

